import 'package:flutter/material.dart';
import 'package:http/http.dart' as http;
import 'package:http/http.dart';

class ApiClient {
  final String _baseUrl = 'https://api.example.com';
  String? _token;

  Future<String> authenticate(String username, String password) async {
    final response = await http.post(Uri.parse('$_baseUrl/login'),
        headers: <String, String>{'content-type': 'application/json'},
        body: jsonEncode({'username': username, 'password': password}));

    if (response.statusCode == 200) {
      _token = response.headers['Authorization']!;
      return _token!; // Return token
    } else {
      throw Exception('Failed to authenticate');
    }
  }

  Future<String> getUserProfile() async {
    final url = Uri.parse('$_baseUrl/user/profile');
    if (_token != null) {
      http.Response? response = await http.get(url,
          headers: <String, String>{
            'Authorization': 'Bearer $_token',
            'content-type': 'application/json'
          });

      return jsonDecode(response!.body)['username'];
    } else {
      throw Exception('No token available');
    }
  }

  Future<String> syncData() async {
    final url = Uri.parse('$_baseUrl/data/sync');
    if (_token != null) {
      http.Response? response =
          await http.get(url, headers: <String, String>{
        'Authorization': 'Bearer $_token',
        'content-type': 'application/json'
      });

      return jsonDecode(response!.body)['syncedData'];
    } else {
      throw Exception('No token available');
    }
  }

  void disposeToken() {
    _token = null;
  }
}

void main() async {
  WidgetsFlutterBinding.ensureInitialized();
  final client = ApiClient();

  await client.authenticate('username', 'password');

  String userProfile = await client.getUserProfile();
  String syncedData = await client.syncData();

  print('User Profile: $userProfile');
  print('Synced Data: $syncedData');
